                        <a:r><a:rPr sz="2400"><a:latin typeface="+mn-cs"/></a:rPr><a:t>MinorComplex</a:t></a:r>
                      </a:p>
                    </p:txBody>
                  </p:sp></p:spTree></p:cSld>
                </p:sld>
